1	/// Epoch-based garbage collector.
2	///
3	/// # Examples
4	///
5	/// ```
6	/// use crossbeam_epoch::Collector;
7	///
8	/// let collector = Collector::new();
9	///
10	/// let handle = collector.register();
11	/// drop(collector); // `handle` still works after dropping `collector`
12	///
13	/// handle.pin().flush();
14	/// ```
15	use core::fmt;
16	
17	use crate::{
18	    guard::Guard,
19	    internal::{Global, Local},
20	    primitive::sync::Arc,
21	};
22	
23	/// An epoch-based garbage collector.
24	pub struct Collector {
25	    pub(crate) global: Arc<Global>,
26	}
27	
28	unsafe impl Send for Collector {}
29	unsafe impl Sync for Collector {}
30	
31	impl Default for Collector {
32	    #[allow(clippy::arc_with_non_send_sync)] // https://github.com/rust-lang/rust-clippy/issues/11382
33	    fn default() -> Self {
34	        Self {
35	            global: Arc::new(Global::new()),
36	        }
37	    }
38	}
39	
40	impl Collector {
41	    /// Creates a new collector.
42	    pub fn new() -> Self {
43	        Self::default()
44	    }
45	
46	    /// Registers a new handle for the collector.
47	    pub fn register(&self) -> LocalHandle {
48	        Local::register(self)
49	    }
50	}
51	
52	impl Clone for Collector {
53	    /// Creates another reference to the same garbage collector.
54	    fn clone(&self) -> Self {
55	        Self {
56	            global: self.global.clone(),
57	        }
58	    }
59	}
60	
61	impl fmt::Debug for Collector {
62	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
63	        f.pad("Collector { .. }")
64	    }
65	}
66	
67	impl PartialEq for Collector {
68	    /// Checks if both handles point to the same collector.
69	    fn eq(&self, rhs: &Self) -> bool {
70	        Arc::ptr_eq(&self.global, &rhs.global)
71	    }
72	}
73	impl Eq for Collector {}
74	
75	/// A handle to a garbage collector.
76	pub struct LocalHandle {
77	    pub(crate) local: *const Local,
78	}
79	
80	impl LocalHandle {
81	    /// Pins the handle.
82	    #[inline]
83	    pub fn pin(&self) -> Guard {
84	        unsafe { (*self.local).pin() }
85	    }
86	
87	    /// Returns `true` if the handle is pinned.
88	    #[inline]
89	    pub fn is_pinned(&self) -> bool {
90	        unsafe { (*self.local).is_pinned() }
91	    }
92	
93	    /// Returns the `Collector` associated with this handle.
94	    #[inline]
95	    pub fn collector(&self) -> &Collector {
96	        unsafe { (*self.local).collector() }
97	    }
98	}
99	
100	impl Drop for LocalHandle {
101	    #[inline]
102	    fn drop(&mut self) {
103	        unsafe {
104	            Local::release_handle(&*self.local);
