282	impl<T> Atomic<T> {
283	    /// Allocates `value` on the heap and returns a new atomic pointer pointing to it.
284	    ///
285	    /// # Examples
286	    ///
287	    /// ```
288	    /// use crossbeam_epoch::Atomic;
289	    ///
290	    /// let a = Atomic::new(1234);
291	    /// # unsafe { drop(a.into_owned()); } // avoid leak
292	    /// ```
293	    pub fn new(init: T) -> Self {
294	        Self::init(init)
295	    }
296	}
