360	    /// Loads a `Shared` from the atomic pointer using a "consume" memory ordering.
361	    ///
362	    /// This is similar to the "acquire" ordering, except that an ordering is
363	    /// only guaranteed with operations that "depend on" the result of the load.
364	    /// However consume loads are usually much faster than acquire loads on
365	    /// architectures with a weak memory model since they don't require memory
366	    /// fence instructions.
367	    ///
368	    /// The exact definition of "depend on" is a bit vague, but it works as you
369	    /// would expect in practice since a lot of software, especially the Linux
370	    /// kernel, rely on this behavior.
371	    ///
372	    /// # Examples
373	    ///
374	    /// ```
375	    /// use crossbeam_epoch::{self as epoch, Atomic};
376	    ///
377	    /// let a = Atomic::new(1234);
378	    /// let guard = &epoch::pin();
379	    /// let p = a.load_consume(guard);
380	    /// # unsafe { drop(a.into_owned()); } // avoid leak
381	    /// ```
382	    pub fn load_consume<'g>(&self, _: &'g Guard) -> Shared<'g, T> {
383	        unsafe { Shared::from_ptr(self.data.load_consume()) }
384	    }
385	
386	    /// Stores a `Shared` or `Owned` pointer into the atomic pointer.
387	    ///
388	    /// This method takes an [`Ordering`] argument which describes the memory ordering of this
389	    /// operation.
390	    ///
391	    /// # Examples
392	    ///
393	    /// ```
394	    /// use crossbeam_epoch::{Atomic, Owned, Shared};
395	    /// use std::sync::atomic::Ordering::SeqCst;
396	    ///
397	    /// let a = Atomic::new(1234);
398	    /// # unsafe { drop(a.load(SeqCst, &crossbeam_epoch::pin()).into_owned()); } // avoid leak
399	    /// a.store(Shared::null(), SeqCst);
400	    /// a.store(Owned::new(1234), SeqCst);
401	    /// # unsafe { drop(a.into_owned()); } // avoid leak
402	    /// ```
403	    pub fn store<P: Pointer<T>>(&self, new: P, order: Ordering) {
404	        self.data.store(new.into_ptr(), order);
405	    }
406	
407	    /// Stores a `Shared` or `Owned` pointer into the atomic pointer, returning the previous
408	    /// `Shared`.
409	    ///
410	    /// This method takes an [`Ordering`] argument which describes the memory ordering of this
411	    /// operation.
412	    ///
413	    /// # Examples
414	    ///
415	    /// ```
416	    /// use crossbeam_epoch::{self as epoch, Atomic, Shared};
417	    /// use std::sync::atomic::Ordering::SeqCst;
418	    ///
419	    /// let a = Atomic::new(1234);
420	    /// let guard = &epoch::pin();
421	    /// let p = a.swap(Shared::null(), SeqCst, guard);
422	    /// # unsafe { drop(p.into_owned()); } // avoid leak
423	    /// ```
424	    pub fn swap<'g, P: Pointer<T>>(&self, new: P, order: Ordering, _: &'g Guard) -> Shared<'g, T> {
425	        unsafe { Shared::from_ptr(self.data.swap(new.into_ptr(), order)) }
426	    }
