632	    /// Bitwise "and" with the current tag.
633	    ///
634	    /// Performs a bitwise "and" operation on the current tag and the argument `val`, and sets the
635	    /// new tag to the result. Returns the previous pointer.
636	    ///
637	    /// This method takes an [`Ordering`] argument which describes the memory ordering of this
638	    /// operation.
639	    ///
640	    /// # Examples
641	    ///
642	    /// ```
643	    /// use crossbeam_epoch::{self as epoch, Atomic, Shared};
644	    /// use std::sync::atomic::Ordering::SeqCst;
645	    ///
646	    /// let a = Atomic::<i32>::from(Shared::null().with_tag(3));
647	    /// let guard = &epoch::pin();
648	    /// assert_eq!(a.fetch_and(2, SeqCst, guard).tag(), 3);
649	    /// assert_eq!(a.load(SeqCst, guard).tag(), 2);
650	    /// ```
651	    pub fn fetch_and<'g>(&self, val: usize, order: Ordering, _: &'g Guard) -> Shared<'g, T> {
652	        let val = val | !low_bits::<T>();
653	        // Ideally, we would always use AtomicPtr::fetch_* since it is strict-provenance
654	        // compatible, but it requires Rust 1.91. So, for now use it only on cfg(miri).
655	        // Code using AtomicUsize::fetch_* via casts is still permissive-provenance
656	        // compatible and is sound.
657	        #[cfg(miri)]
658	        unsafe {
659	            Shared::from_ptr(self.data.fetch_and(val, order))
660	        }
661	        #[cfg(not(miri))]
662	        unsafe {
663	            Shared::from_ptr(
664	                (*(&self.data as *const AtomicPtr<_> as *const AtomicUsize)).fetch_and(val, order)
665	                    as *mut (),
666	            )
667	        }
668	    }
