790	    /// # Safety
791	    ///
792	    /// This method may be called only if the pointer is valid and nobody else is holding a
793	    /// reference to the same object, or the pointer is null.
794	    ///
795	    /// # Examples
796	    ///
797	    /// ```rust
798	    /// # use std::mem;
799	    /// # use crossbeam_epoch::Atomic;
800	    /// struct DataStructure {
801	    ///     ptr: Atomic<usize>,
802	    /// }
803	    ///
804	    /// impl Drop for DataStructure {
805	    ///     fn drop(&mut self) {
806	    ///         // By now the DataStructure lives only in our thread and we are sure we don't hold
807	    ///         // any Shared or & to it ourselves, but it may be null, so we have to be careful.
808	    ///         let old = mem::take(&mut self.ptr);
809	    ///         unsafe {
810	    ///             if let Some(x) = old.try_into_owned() {
811	    ///                 drop(x)
812	    ///             }
813	    ///         }
814	    ///     }
815	    /// }
816	    /// ```
