205	impl<T> Drop for Queue<T> {
206	    fn drop(&mut self) {
207	        unsafe {
208	            let guard = unprotected();
209	
210	            while self.try_pop(guard).is_some() {}
211	
212	            // Destroy the remaining sentinel node.
213	            let sentinel = self.head.load(Relaxed, guard);
214	            drop(sentinel.into_owned());
215	        }
216	    }
217	}
